import React, { Component, } from 'react'
import { Bar } from 'react-chartjs-2'


class BarChart extends Component {

    constructor(props) {
        super(props);

        this.state = {
            predictions: [],
            avgPrice: null,
            avgRating: null,
            soldUnits: null,
        };
    }

    componentDidMount() {
        var { keywords } = this.props;
        var { country } = this.props;
        var url = 'api/chart?keywords=' + keywords + '&country=' + country;
        console.log('URL is' + " " + url)
        fetch(url)
            .then(res => res.json())
            .then(data => this.setState({
                predictions: data.predictions,
                avgPrice: data.avgPrice,
                avgRating: data.avgRating,
                soldUnits: data.soldUnits
            }));



    }
    render() {
        return (
            <div>
                <Bar
                    data={{
                        labels: ['Positive', 'Negative'],
                        datasets: [
                            {
                                label: 'Sentiment Review',
                                data: this.state.predictions,
                                backgroundColor: [
                                    'rgba(255, 99, 132, 0.2)',
                                    'rgba(54, 162, 235, 0.2)',

                                ],
                                borderColor: [
                                    'rgba(255, 99, 132, 0.2)',
                                    'rgba(54, 162, 235, 0.2)',
                                ],
                                borderWidth: 1,
                            }
                        ]
                    }}
                    height={400}
                    width={600}
                    options={{
                        maintainAspectRatio: false,
                        scales: {
                            yAxes: [
                                {
                                    ticks: {
                                        beginAtZero: true
                                    }
                                }
                            ]
                        }
                    }}
                />
                <div>Average Price: {this.state.avgPrice}</div>
                <div>Average Rating: {this.state.avgRating}</div>
                <div>Sold Units: {this.state.soldUnits}</div>
            </div>
        );
    }
}

export default BarChart
